@charset "UTF-8";
:root {
  --bg-color: #f4f7f6;
  --card-bg: #ffffff;
  --primary: #2c3e50;
  --accent: #3498db;
  --text: #333;
  --border: #ddd;
  --critical: #c0392b;
  --warning: #f39c12;
  --safe: #27ae60;
  --info: #2980b9;
  --muted: #7f8c8d;
}

* {
  box-sizing: border-box;
}

body {
  font-family: "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;
  background-color: var(--bg-color);
  color: var(--text);
  margin: 0;
  padding: 20px;
}

header {
  text-align: center;
  margin-bottom: 30px;
  color: var(--primary);
}

header h2 {
  font-size: 1.5rem;
  margin: 0 0 6px;
}

header p {
  margin-top: 0;
  color: var(--muted);
  font-size: 1.05rem;
  max-width: 760px;
  margin-left: auto;
  margin-right: auto;
}

/* KPI cards */
.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 20px;
  margin-bottom: 30px;
}

.card {
  background: var(--card-bg);
  padding: 20px;
  border-radius: 8px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.08);
  text-align: center;
  border-top: 4px solid var(--accent);
}

.card h3 {
  margin: 0;
  font-size: 0.95rem;
  color: var(--muted);
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

.card p {
  font-size: 2.2rem;
  font-weight: bold;
  margin: 10px 0 2px;
  color: var(--primary);
}

.card-sub {
  font-size: 0.8rem;
  color: var(--muted);
  text-transform: uppercase;
  letter-spacing: 0.03em;
}

/* Two column panels */
.two-col {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
  gap: 20px;
  margin-bottom: 30px;
}

.panel {
  background: var(--card-bg);
  padding: 20px;
  border-radius: 8px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.08);
}

.panel h3 {
  margin-top: 0;
  color: var(--primary);
}

/* Horizontal bars */
.bars {
  display: flex;
  flex-direction: column;
  gap: 12px;
  margin-top: 6px;
}

.bar-empty {
  color: var(--muted);
  font-size: 0.95rem;
}

.bar-row {
  display: grid;
  grid-template-columns: 130px 1fr 42px;
  align-items: center;
  gap: 10px;
}

.bar-label {
  font-size: 0.9rem;
  color: var(--text);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.bar-track {
  background: #eef1f3;
  border-radius: 5px;
  height: 16px;
  overflow: hidden;
}

.bar-fill {
  height: 100%;
  border-radius: 5px;
  background: var(--accent);
  transition: width 0.4s ease;
}

.bar-count {
  font-size: 0.9rem;
  font-weight: 600;
  color: var(--primary);
  text-align: right;
}

/* Findings */
.findings-container {
  background: var(--card-bg);
  padding: 20px;
  border-radius: 8px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.08);
  margin-bottom: 30px;
  border-left: 5px solid var(--warning);
}

.findings-container h3 {
  margin-top: 0;
  color: var(--primary);
}

.findings-list {
  list-style-type: none;
  padding-left: 0;
  margin: 0;
}

.findings-list li {
  padding: 12px 0;
  border-bottom: 1px solid var(--border);
  font-size: 1.02rem;
  line-height: 1.55;
}

.findings-list li:last-child {
  border-bottom: none;
}

.findings-list li::before {
  content: "•";
  color: var(--accent);
  font-weight: bold;
  margin-right: 10px;
}

/* Coverage gap callout */
.gap-container {
  background: #eaf4fb;
  padding: 20px;
  border-radius: 8px;
  border-left: 5px solid var(--info);
  margin-bottom: 30px;
}

.gap-container h3 {
  margin-top: 0;
  color: var(--info);
}

.gap-container p {
  margin: 8px 0;
  line-height: 1.55;
}

.gap-forward {
  font-size: 0.95rem;
  color: #34495e;
}

/* Table */
.table-container {
  background: var(--card-bg);
  padding: 20px;
  border-radius: 8px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.08);
  overflow-x: auto;
}

.table-container h3 {
  margin-top: 0;
  color: var(--primary);
}

table {
  width: 100%;
  border-collapse: collapse;
  margin-top: 10px;
}

th, td {
  text-align: left;
  padding: 12px;
  border-bottom: 1px solid var(--border);
  vertical-align: top;
}

th {
  background-color: #f8f9fa;
  color: var(--primary);
}

.badge {
  padding: 4px 8px;
  border-radius: 4px;
  font-size: 0.9rem;
  font-weight: bold;
  display: inline-block;
}

.badge-critical {
  background: #f8d7da;
  color: #721c24;
  border: 1px solid #f5c6cb;
}

.badge-warning {
  background: #fff3cd;
  color: #856404;
  border: 1px solid #ffeeba;
}

.badge-safe {
  background: #d4edda;
  color: #155724;
  border: 1px solid #c3e6cb;
}

.badge-low {
  background: #d6eaf8;
  color: #1b4f72;
  border: 1px solid #aed6f1;
}

code {
  background: #eee;
  padding: 2px 4px;
  border-radius: 3px;
  font-family: monospace;
  font-size: 0.9rem;
  color: #d63031;
}

