appsmith.onReady(() => {
    appsmith.onModelChange((model) => {
        // --- Resolve the report object regardless of how it's bound ---
        const root = model || {};
        const report = root.data && root.data.findings ? root.data
                     : (root.findings ? root : (root.data || {}));

        const totals     = report.totals || {};
        const inventory  = report.inventory || {};
        const findings   = Array.isArray(report.findings) ? report.findings : [];
        const gap        = report.honest_gap || null;
        const agg        = report.aggregate_summary || {};
        const allRepos   = Array.isArray(report.repo) ? report.repo : [];
        const reposUsingAIList = inventory.repos_using_ai || [];

        const reposScanned  = report.repos_scanned || allRepos.length || 0;
        const reposUsingAI  = reposUsingAIList.length;
        const totalFindings = totals.findings != null ? totals.findings : findings.length;

        // =====================================================================
        // CONFIG — presentation/scale only.
        // The exposure index comes straight from the report (aggregate_summary);
        // per-finding risk_score (3.3 = low) confirms a CVSS-style 0–10 scale.
        // =====================================================================
        const CONFIG = {
            indexScale: 100,
            indexMultiplier: 10,                         // report index (0–10) shown on a 0–100 card
            indexBands: { high: 70, medium: 40 },
            indexColors: { high: 'var(--critical)', medium: 'var(--warning)', low: 'var(--safe)' },
            severityOrder: { critical: 0, high: 1, medium: 2, low: 3, unknown: 4 },
            familyBarColor: '#9b59b6',
            dirBarColor: '#e67e22'
        };
        const worseSev = (a, b) =>
            (CONFIG.severityOrder[a] ?? 9) <= (CONFIG.severityOrder[b] ?? 9) ? a : b;

        // --- Tally categories / patterns ------------------------------------
        let weightPulls = 0;
        let mlDeps = 0;
        const sevCount = {};
        const providerSet = new Set();
        findings.forEach(f => {
            const cat = f.category || '';
            const meta = f.metadata || {};
            if (cat === 'hf_import' || meta.pattern === 'from_pretrained') weightPulls++;
            if (cat === 'ml_dependency' || meta.dependency) mlDeps++;
            const s = (f.severity || 'unknown').toLowerCase();
            sevCount[s] = (sevCount[s] || 0) + 1;
            if (f.provider) providerSet.add(f.provider);
        });
        const worstSeverity = ['critical', 'high', 'medium', 'low']
            .find(s => sevCount[s]) || 'none';

        // --- Exposure Index: the report's OWN score (no homemade composite) --
        const rawIndex = agg.exposure_index_mean != null ? agg.exposure_index_mean
                       : (agg.exposure_index_max != null ? agg.exposure_index_max : null);
        const reportIndex = rawIndex == null ? null : Math.round(rawIndex * CONFIG.indexMultiplier);
        const indexBand = reportIndex == null ? 'low'
                        : reportIndex >= CONFIG.indexBands.high ? 'high'
                        : reportIndex >= CONFIG.indexBands.medium ? 'medium' : 'low';

        // --- Header ---------------------------------------------------------
        document.getElementById('scan-title').innerText = 'AI Discovery';
        const surfaces = (report.surfaces_run || []).join(', ') || '—';
        const surfaceBreak = Object.entries(totals.by_surface || {})
            .map(([s, n]) => `${s} (${n})`).join(', ');
        const sources = [...providerSet].join(', ') || '—';
        const shortId = (report.scan_name || '').split('-')[0] || report.scan_name || '—';
        document.getElementById('scan-subtitle').innerText =
            `Scan ${shortId} · surfaces: ${surfaces}${surfaceBreak ? ` [${surfaceBreak}]` : ''} · source: ${sources} · ` +
            `${agg.scored_items != null ? agg.scored_items : totalFindings} findings scored across ${agg.files_merged != null ? agg.files_merged : reposScanned} merged sources.`;

        // --- KPI cards ------------------------------------------------------
        const idxEl = document.getElementById('kpi-exposure');
        idxEl.innerText = reportIndex == null ? '—' : `${reportIndex} / ${CONFIG.indexScale}`;
        idxEl.style.color = CONFIG.indexColors[indexBand];
        document.getElementById('kpi-exposure-sub').innerText =
            `${indexBand} exposure · report index`;

        document.getElementById('kpi-findings').innerText = totalFindings;
        const sevBreak = Object.entries(totals.by_severity || {})
            .map(([s, n]) => `${n} ${s}`).join(', ') || `worst: ${worstSeverity}`;
        document.getElementById('kpi-findings-sub').innerText = sevBreak;

        document.getElementById('kpi-repos').innerText = `${reposUsingAI}/${reposScanned}`;
        document.getElementById('kpi-repos-sub').innerText = 'repos use AI';

        document.getElementById('kpi-pulls').innerText = weightPulls;
        document.getElementById('kpi-pulls-sub').innerText = 'remote from_pretrained';

        // --- Model family footprint -----------------------------------------
        const families = [
            { label: 'BERT',        match: e => /\bbert/.test(e) && !/distilbert|squeezebert/.test(e) },
            { label: 'DistilBERT',  match: e => /distilbert/.test(e) },
            { label: 'SqueezeBERT', match: e => /squeezebert/.test(e) },
            { label: 'GPT-2',       match: e => /gpt-?2/.test(e) },
            { label: 'Wav2Vec2',    match: e => /wav2vec2/.test(e) },
            { label: 'transformers',match: e => /transformers==/.test(e) }
        ];
        const famCounts = {};
        findings.forEach(f => {
            const e = (f.evidence || '').toLowerCase();
            for (const fam of families) {
                if (fam.match(e)) { famCounts[fam.label] = (famCounts[fam.label] || 0) + 1; break; }
            }
        });
        renderBars('family-bars', famCounts, CONFIG.familyBarColor);

        // --- Hotspot directories --------------------------------------------
        const dirCounts = {};
        findings.forEach(f => {
            const path = f.file_path || '';
            const repoShort = (f.repo || '').split('/').pop();
            const top = path.indexOf('/') > -1 ? path.split('/')[0] : path;
            dirCounts[`${repoShort}/${top}`] = (dirCounts[`${repoShort}/${top}`] || 0) + 1;
        });
        renderBars('dir-bars', dirCounts, CONFIG.dirBarColor);

        // --- Key findings ---------------------------------------------------
        const list = document.getElementById('findings-list');
        list.innerHTML = '';
        const items = [];

        if (reposUsingAI > 0) {
            items.push(`<strong>AI footprint:</strong> ${reposUsingAI} of ${reposScanned} scanned repositories pull AI models or libraries — ${reposUsingAIList.map(r => `<code>${r}</code>`).join(', ')}.`);
        }
        const reposNoAI = allRepos.filter(r => !reposUsingAIList.includes(r));
        if (reposNoAI.length > 0) {
            items.push(`<strong>No AI usage:</strong> ${reposNoAI.length} of ${reposScanned} scanned repositories showed no AI footprint — ${reposNoAI.map(r => `<code>${r}</code>`).join(', ')}.`);
        }
        if (weightPulls > 0) {
            const devs = inventory.developers_pulling_weights || [];
            const devNote = devs.length
                ? ` Attributed to ${devs.length} developer(s): ${devs.map(x => `<code>${x}</code>`).join(', ')}.`
                : ' No individual developer attribution recorded for these pulls.';
            items.push(`<strong>Remote weight loading:</strong> ${weightPulls} <code>from_pretrained</code> calls fetch model weights from the Hugging Face Hub at runtime.${devNote} Unpinned references can shift under you and expand the supply-chain surface.`);
        }
        if (mlDeps > 0) {
            const depStr = Object.entries(inventory.ai_dependency_chain || {})
                .map(([k, v]) => `<code>${k}</code> (${v})`).join(', ') || 'AI/ML packages';
            items.push(`<strong>Declared AI dependencies:</strong> ${mlDeps} pinned AI/ML dependency finding(s) across ${depStr}. Track these in your SBOM and watch for CVEs against the pinned versions.`);
        }
        const actors = [...new Set(findings.map(f => f.actor).filter(Boolean))];
        if (actors.length === 1 && findings.length > 1) {
            items.push(`<strong>Concentrated ownership:</strong> all ${findings.length} findings trace to a single account (<code>${actors[0]}</code>) — a governance and bus-factor consideration for AI assets.`);
        }
        if (reportIndex != null) {
            items.push(`<strong>Scanner exposure rating:</strong> the report scores this scan at <code>${reportIndex}/${CONFIG.indexScale}</code> (${indexBand}) across ${agg.scored_items != null ? agg.scored_items : totalFindings} scored items — a broad but low-severity discovery footprint.`);
        }
        if (gap && gap.status === 'not_covered') {
            items.push(`<strong>Known blind spot:</strong> the <code>${gap.surface}</code> surface is not covered by this scan.`);
        }

        if (items.length === 0) {
            list.innerHTML = '<li style="color: var(--safe);">No AI usage or boundary issues detected in scanned surfaces.</li>';
        } else {
            items.forEach(html => {
                const li = document.createElement('li');
                li.innerHTML = html;
                list.appendChild(li);
            });
        }

        // --- Coverage gap card removed; keep its container hidden -----------
        const gapBox = document.getElementById('gap-container');
        if (gapBox) gapBox.style.display = 'none';

        // --- File hotspots table --------------------------------------------
        const tbody = document.getElementById('hotspot-table-body');
        tbody.innerHTML = '';
        const byFile = {};
        findings.forEach(f => {
            const k = f.file_path || '(unknown)';
            if (!byFile[k]) {
                byFile[k] = { count: 0, repo: f.repo || '', category: f.category || '',
                              severity: (f.severity || 'low').toLowerCase(), maxRisk: 0,
                              title: f.title || '', lines: [] };
            }
            const e = byFile[k];
            e.count++;
            e.severity = worseSev(e.severity, (f.severity || 'low').toLowerCase());
            if (typeof f.risk_score === 'number') e.maxRisk = Math.max(e.maxRisk, f.risk_score);
            if (f.line != null) e.lines.push(f.line);
        });
        const rows = Object.entries(byFile)
            .map(([file, v]) => ({ file, ...v }))
            .sort((a, b) => b.maxRisk - a.maxRisk || b.count - a.count);

        const badgeFor = (sev) => ({
            critical: 'badge-critical', high: 'badge-warning',
            medium: 'badge-warning', low: 'badge-low'
        })[(sev || '').toLowerCase()] || 'badge-safe';
        const actionFor = (cat) => cat === 'ml_dependency'
            ? 'Pin & track in SBOM; monitor CVEs and upgrade the version.'
            : 'Pin model revisions (commit hash) and load from an internal mirror/registry.';

        if (rows.length === 0) {
            tbody.innerHTML = '<tr><td colspan="5" style="text-align:center;">No file-level findings.</td></tr>';
        } else {
            rows.forEach(r => {
                const tr = document.createElement('tr');
                const fileName = r.file.split('/').pop();
                const lineNote = r.lines.length
                    ? ` · L${Math.min(...r.lines)}${r.lines.length > 1 ? '–L' + Math.max(...r.lines) : ''}`
                    : '';

                // File / Context (filename, path, real finding title)
                const tdFile = document.createElement('td');
                const strong = document.createElement('strong');
                strong.textContent = fileName;
                tdFile.appendChild(strong);
                const path = document.createElement('span');
                path.style.cssText = 'color:var(--muted);font-size:.85rem;display:block;';
                path.textContent = r.file + lineNote;
                tdFile.appendChild(path);
                if (r.title) {
                    const title = document.createElement('span');
                    title.style.cssText = 'color:var(--muted);font-size:.8rem;display:block;';
                    title.textContent = r.title;
                    tdFile.appendChild(title);
                }

                // Repo
                const tdRepo = document.createElement('td');
                const codeRepo = document.createElement('code');
                codeRepo.textContent = (r.repo || '').split('/').pop();
                tdRepo.appendChild(codeRepo);

                // Findings count
                const tdCount = document.createElement('td');
                tdCount.textContent = r.count;

                // Severity + real risk_score
                const tdSev = document.createElement('td');
                const badge = document.createElement('span');
                badge.className = `badge ${badgeFor(r.severity)}`;
                badge.textContent = `${(r.severity || 'low').toUpperCase()}${r.maxRisk ? ' · ' + r.maxRisk : ''}`;
                tdSev.appendChild(badge);

                // Action
                const tdAction = document.createElement('td');
                tdAction.textContent = actionFor(r.category);

                tr.append(tdFile, tdRepo, tdCount, tdSev, tdAction);
                tbody.appendChild(tr);
            });
        }
    });

    // Helper: render {label: count} as horizontal bars (sorted desc)
    function renderBars(containerId, counts, color) {
        const el = document.getElementById(containerId);
        const entries = Object.entries(counts).sort((a, b) => b[1] - a[1]);
        if (entries.length === 0) { el.innerHTML = '<div class="bar-empty">No data.</div>'; return; }
        const max = Math.max(...entries.map(e => e[1]));
        el.innerHTML = '';
        entries.forEach(([label, count]) => {
            const pct = Math.max(6, Math.round((count / max) * 100));
            const row = document.createElement('div');
            row.className = 'bar-row';
            row.innerHTML =
                `<div class="bar-label" title="${label}">${label}</div>` +
                `<div class="bar-track"><div class="bar-fill" style="width:${pct}%;background:${color};"></div></div>` +
                `<div class="bar-count">${count}</div>`;
            el.appendChild(row);
        });
    }
});
